// src/data/spells.ts
export interface Spell {
  id: string;
  name: string;
  frenchName: string;
  category: "Combat" | "Detection" | "Illusion" | "Manipulation" | "Health" | "Other";
  type: "Mana" | "Physical";
  drain: string;
  range: string;
  duration: string;
  page: number;
  description?: string;
}

export const ALL_SPELLS: Spell[] = [
// ==================== A ====================
  { id: "agony", name: "Agony", frenchName: "Agonie", category: "Combat", type: "Mana", drain: "3", range: "LOS", duration: "Special", page: 13, description: "This spell inflicts suffering, but without really injuring the target. Make a Sorcery + Magic test against Willpower + Logic; each net success acts as if one box was checked on the stun and physical damage monitors to determine the wound penalty. If all boxes on one or both monitors are checked, the targeted individual remains conscious but suffers so much that they cannot act. Once the spell is dropped, the target suffers no further side effects from the pain.\nThe base spell affects only one individual, but the Area Extension effect can be used to turn it into an area spell (starting with a 2-meter radius for +1 Drain). When it is an area spell, the Area Displacement effect can be used." },
  { id: "analyze-magic", name: "Analyze Magic", frenchName: "Analyse de la magie", category: "Detection", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 7, description: "Sometimes you need to know what a magical effect does without perceiving the astral. Consider this spell as if you were using astral observation (see p. 162, SR6). The test is opposed by 2 × the total successes of the original skill test (Conjuring, Enchanting or Sorcery) that generated the magical effect you are analyzing." },
  { id: "analyze-truth", name: "Analyze Truth", frenchName: "Analyse de la véracité", category: "Detection", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 7, description: "The subject of the spell can sense whether the target is telling the truth or at least believes they are. With at least 1 net success, you know. Note that the spell subject must be able to hear directly what is being said to evaluate it. Written statements, recordings or audio/video transmissions cannot be analyzed. Because it's mana, that's why." },
  { id: "analyze-object", name: "Analyze Object", frenchName: "Analyse d'objet", category: "Detection", type: "Mana", drain: "2", range: "Touch", duration: "Sustained", page: 7, description: "Of course you know what a commlink looks like, but that doesn't mean you can identify the function of this strange black box with a single connector. And may the spirits help you if you are faced with a machine from the 1950s. Analyze Object gives you information about unknown objects based on the number of net successes you obtain (the device's resistance is used for the opposed test). The first time a character tries to use a device while sustaining this spell, they gain a number of Edge points equal to their net successes on that test (cannot exceed the limit of 2 Edge points per turn)." },
  { id: "anaphylaxis", name: "Anaphylaxis", frenchName: "Anaphylaxie", category: "Health", type: "Physical", drain: "5", range: "Contact", duration: "Permanent", page: 10, description: "To cast Anaphylaxis, make an opposed Sorcery + Magic test against Constitution + Willpower. Casting Ephedrine is a simple Sorcery + Magic (5 — Essence) test. For every two net successes, the severity of the allergic reaction increases (Anaphylaxis) or decreases (Ephedrine) by one level (p. 76, SR6). The first two successes cause a mild severity allergic reaction (to the substance chosen by the magician at the time of casting) as long as the spell is sustained.\nWhen it is no longer used, the allergic reaction returns to a normal level or disappears if no active allergen is present.\nIf, for example, a subject with a deadly allergy to shellfish eats some for some reason, then Ephedrine must be sustained until the most severe symptoms pass (about eight hours) or regular medicine is applied. Otherwise, the deadly allergy returns.\nEphedrine can be used against all allergies." },
  { id: "animate-stone", name: "Animate Stone", frenchName: "Animation de la pierre", category: "Manipulation", type: "Physical", drain: "5", range: "LdV", duration: "Sustained", page: 17, description: "A piece of the affected material type animates and moves according to the spellcaster's instructions. Make a Sorcery + Magic test against the Object Resistance of the animated object/material. You can shape ½ cubic meter of material per net success (see the Volume table at the top of this page for more information). The material can move according to its shape, but generally cannot go faster than 5 meters per combat round unless it has wheels or something that allows it to go faster. The object is generally incapable of coordinated movements so its attacks are slow and can be easily blocked.\nIt can however strike an immobile target or one unaware of the danger, inflicting 4P damage if it is metal, 3P if stone, 2S if wood and 1S if plastic.\nCommanding the animated substance requires a Minor Action. If someone tries to prevent the object from obeying your orders, use the net successes of the Spellcasting test, +4 (for metal), +3 (for stone), +2 (for wood) and +1 (for plastic) against Constitution + Strength to know if the object is prevented from acting to respond to that order.\nChoosing the right spell can be tricky if an object is not made of a single material; a table may be wood or plastic but have metal elements. In that case, choose the dominant material in the object to animate and use the corresponding spell. The magic that imbues the majority material is powerful enough to animate the others." },
  { id: "animate-wood", name: "Animate Wood", frenchName: "Animation du bois", category: "Manipulation", type: "Physical", drain: "4", range: "LdV", duration: "Sustained", page: 16, description: "A piece of the affected material type animates and moves according to the spellcaster's instructions. Make a Sorcery + Magic test against the Object Resistance of the animated object/material. You can shape ½ cubic meter of material per net success (see the Volume table at the top of this page for more information). The material can move according to its shape, but generally cannot go faster than 5 meters per combat round unless it has wheels or something that allows it to go faster. The object is generally incapable of coordinated movements so its attacks are slow and can be easily blocked.\nIt can however strike an immobile target or one unaware of the danger, inflicting 4P damage if it is metal, 3P if stone, 2S if wood and 1S if plastic.\nCommanding the animated substance requires a Minor Action. If someone tries to prevent the object from obeying your orders, use the net successes of the Spellcasting test, +4 (for metal), +3 (for stone), +2 (for wood) and +1 (for plastic) against Constitution + Strength to know if the object is prevented from acting to respond to that order.\nChoosing the right spell can be tricky if an object is not made of a single material; a table may be wood or plastic but have metal elements. In that case, choose the dominant material in the object to animate and use the corresponding spell. The magic that imbues the majority material is powerful enough to animate the others." },
  { id: "animate-metal", name: "Animate Metal", frenchName: "Animation du métal", category: "Manipulation", type: "Physical", drain: "5", range: "LdV", duration: "Sustained", page: 16, description: "A piece of the affected material type animates and moves according to the spellcaster's instructions. Make a Sorcery + Magic test against the Object Resistance of the animated object/material. You can shape ½ cubic meter of material per net success (see the Volume table at the top of this page for more information). The material can move according to its shape, but generally cannot go faster than 5 meters per combat round unless it has wheels or something that allows it to go faster. The object is generally incapable of coordinated movements so its attacks are slow and can be easily blocked.\nIt can however strike an immobile target or one unaware of the danger, inflicting 4P damage if it is metal, 3P if stone, 2S if wood and 1S if plastic.\nCommanding the animated substance requires a Minor Action. If someone tries to prevent the object from obeying your orders, use the net successes of the Spellcasting test, +4 (for metal), +3 (for stone), +2 (for wood) and +1 (for plastic) against Constitution + Strength to know if the object is prevented from acting to respond to that order.\nChoosing the right spell can be tricky if an object is not made of a single material; a table may be wood or plastic but have metal elements. In that case, choose the dominant material in the object to animate and use the corresponding spell. The magic that imbues the majority material is powerful enough to animate the others." },
  { id: "animate-plastic", name: "Animate Plastic", frenchName: "Animation du plastique", category: "Manipulation", type: "Physical", drain: "3", range: "LdV", duration: "Sustained", page: 17, description: "A piece of the affected material type animates and moves according to the spellcaster's instructions. Make a Sorcery + Magic test against the Object Resistance of the animated object/material. You can shape ½ cubic meter of material per net success (see the Volume table at the top of this page for more information). The material can move according to its shape, but generally cannot go faster than 5 meters per combat round unless it has wheels or something that allows it to go faster. The object is generally incapable of coordinated movements so its attacks are slow and can be easily blocked.\nIt can however strike an immobile target or one unaware of the danger, inflicting 4P damage if it is metal, 3P if stone, 2S if wood and 1S if plastic.\nCommanding the animated substance requires a Minor Action. If someone tries to prevent the object from obeying your orders, use the net successes of the Spellcasting test, +4 (for metal), +3 (for stone), +2 (for wood) and +1 (for plastic) against Constitution + Strength to know if the object is prevented from acting to respond to that order.\nChoosing the right spell can be tricky if an object is not made of a single material; a table may be wood or plastic but have metal elements. In that case, choose the dominant material in the object to animate and use the corresponding spell. The magic that imbues the majority material is powerful enough to animate the others." },
  { id: "anti-detect", name: "Anti-Detect", frenchName: "Anti-détecteurs", category: "Illusion", type: "Mana", drain: "2", range: "LOS", duration: "Sustained", page: 14, description: "Improved Invisibility, Improved Mask and other spells of this type are perfect when you want to hide from both eyes and technological devices, but what if there is no living being around and only cameras, detectors and such devices? Anti-Detectors is the spell you need. It grants the target a version of the Invisible (Improved) status, but it has no effect on living conscious beings — only on technological detectors." },
  { id: "antidote", name: "Antidote", frenchName: "Antidote", category: "Health", type: "Mana", drain: "5", range: "Contact", duration: "Permanent", page: 10, description: "This spell releases mana that travels through the body to dissolve and purge toxins. Make an extended Sorcery + Magic test (Virulence, 1 round), each success reducing the toxin's Virulence by one point. If the toxin's Virulence is reduced to zero, it is eliminated. Each roll is a Major Action, but the Drain is only suffered once, on the first action, as the spell is only cast once." },
  { id: "armor", name: "Armor", frenchName: "Armure", category: "Manipulation", type: "Physical", drain: "4", range: "LOS", duration: "Sustained", page: 17, description: "Your magic infuses the target's body, strengthening it so it can better withstand damage. Make a Sorcery + Magic test and add the net successes to the target's Defense Score." },
  { id: "astral-armor", name: "Astral Armor", frenchName: "Armure astrale", category: "Manipulation", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 17, description: "You magically strengthen a target's astral form so it can better withstand damage. Make a Sorcery + Magic test and add the net successes to its Defense Score in astral combat or against mana-based combat spells." },
  { id: "vehicle-armor", name: "Vehicle Armor", frenchName: "Armure de véhicule", category: "Manipulation", type: "Physical", drain: "6", range: "Contact", duration: "Sustained", page: 17, description: "To cast this spell, make an opposed Sorcery + Magic test against the vehicle's Object Resistance. The vehicle gains one point of Reinforced Armor (p. 229, SR6) per net success." },
  { id: "elemental-armor", name: "Elemental Armor", frenchName: "Armure élémentaire", category: "Manipulation", type: "Physical", drain: "5", range: "Contact", duration: "Sustained", page: 17, description: "Like the Armor spell (above), make a Sorcery + Magic test and add the net successes to the target's Defense Score. In addition, it adds an extra bonus. When you cast it, you choose an element against which the target will be protected. Depending on your choice, the target can no longer suffer certain conditions as indicated in the Elemental Protection table. The target can still be injured by a weapon or spell that inflicts that type of damage; for example, if it benefits from a chilling armor, it can still be injured by a Fireball if the initial attack test succeeds and it does not soak all the damage, but it will not suffer the Burning condition." },
  { id: "attribute-boost", name: "Attribute Boost", frenchName: "Augmentation d'attribut", category: "Manipulation", type: "Physical", drain: "3", range: "Contact", duration: "Sustained", page: 10, description: "The mage's touch strengthens or accelerates the target's abilities, temporarily increasing one of its attributes. The spellcaster decides which attribute will be affected before casting the spell. Then they make a Sorcery + Magic (5 - Essence) test, which provides an automatic success if the target has an Essence of 6. The mage can choose the number of net successes to use to increase the attribute at a rate of 1 point of increase per net success (maximum bonus of +4); for each net success used after the first, the spell's Drain is increased by 1 point. This spell cannot affect Edge, Essence, Magic or Resonance." },
  { id: "reflexes-boost", name: "Reflexes Boost", frenchName: "Augmentation de réflexes", category: "Manipulation", type: "Physical", drain: "5", range: "Contact", duration: "Sustained", page: 10, description: "The target increases its speed and reacts faster, allowing it to better anticipate situations and react more quickly to the actions of others. The spellcaster makes a Sorcery + Magic (Essence) test, which provides an automatic success if the target has an Essence of 6. The mage can choose the number of net successes to use to increase both the Reaction rating and the number of Initiative dice of the target at a rate of 1 point of increase and 1 Initiative die per net success without being able to exceed 5 Initiative dice. Each Initiative die gained through this spell provides an additional Minor Action, as described on p. 43, SR6. For each net success used after the first, the spell's Drain is increased by 1 point. The effects of this spell do not apply in virtual reality." },

// ==================== B ====================
  { id: "mana-barrier", name: "Mana Barrier", frenchName: "Barrière mana", category: "Manipulation", type: "Mana", drain: "5", range: "LdV (Z)", duration: "Sustained", page: 17, description: "You want no spirit to be able to enter this room? You want to enforce your \"no foci\" policy in your bar? Then the Mana Barrier can be useful to you. This spell creates a mana barrier on the physical or astral plane, at the magician's choice, whose effects are described on p. 164, SR6. To cast a Mana Barrier, make a Sorcery + Magic test; the Structure rating of the astral wall you create is equal to (net successes + Magic of the caster).\nBy default, this spell generates a barrier of two meters by two meters and two centimeters thick. Area Extension can allow adding two meters in length and width (but not in thickness) each time this effect is chosen. The spellcaster can choose the shape of their barrier as they wish.\nFor more information on mana barriers, see p. 164, SR6." },
  { id: "physical-barrier", name: "Physical Barrier", frenchName: "Barrière physique", category: "Manipulation", type: "Physical", drain: "6", range: "LdV (Z)", duration: "Sustained", page: 18, description: "Sometimes you want to keep magic at bay and other times you want nothing to be able to approach you. Physical Barrier creates a wall where you want it to be with a Structure rating equal to (Magic + successes on a Sorcery + Magic test). The base spell generates a barrier of two meters by two meters and two centimeters thick. Area Extension can allow adding two meters in length and width (but not in thickness) each time this effect is chosen." },
  { id: "boil-object", name: "Boil Object", frenchName: "Bouillie (objet)", category: "Manipulation", type: "Physical", drain: "4", range: "Touch", duration: "Permanent", page: 4, description: "These spells must incorporate an object into the spell formula (firearm, commlink, armor, etc.). The chosen object can be precise or vague. See the table below for examples of objects that can be destroyed by these spells.\nThey can be learned multiple times by choosing a new object.\nYou gain 1 Edge point when casting the spell, if the object is precise rather than vague (e.g. heavy pistol instead of firearms).\nDirect area spells target all objects that match the criterion and are visible to the magician, unlike indirect spells which affect all objects in the area, visible or not.\nCorrosion, Fusion and Pulp are indirect combat spells (p. 4), which means that a targeted object belonging to someone cannot avoid the spell (p. 136, SR6). To cast these spells, you must make a Sorcery + Magic test against the Reaction + Willpower of the subject who controls the object (or Piloting + Evasion in the case of remotely controlled vehicles). The object will resist damage with its Structure rating (see effect table). They inflict chemical damage (p. 114, SR6) and subject the targets to the Corroded condition (p. 55, SR6) with a rating equal to the net successes on the Sorcery test.\nSmash, Dismantle and Demolish are direct combat spells (p. 3). To cast these spells, you must make a Sorcery + Magic test against the object's Resistance rating. It cannot resist damage." },
  { id: "camouflage", name: "Camouflage", frenchName: "Brouillage", category: "Illusion", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 14, description: "This spell is resisted with an opposed Matrix + Firewall test (or Matrix + Willpower if actively protected, Willpower + Logic if the target is a technomancer).\nIf you cast this spell successfully, Jamming inflicts 1 point of Matrix Noise in its area of effect per net success on the Sorcery test. Any wireless signal passing through the area of effect is affected." },

  // ==================== C ====================
  { id: "catalog", name: "Catalog", frenchName: "Catalogue", category: "Detection", type: "Mana", drain: "5", range: "Contact", duration: "Sustained", page: 9, description: "This spell allows the caster to be extremely focused on an object or an area. The Carefully Observe action becomes a Minor Action when the spell is sustained and used on the chosen object (Inspection) or area (Catalogue).\nThese spells allow obtaining more details with Carefully Observe.\nEach net success offers one type of detail that can be detected. You will find a list below, from which the magician can make their choice.\nWhen the Catalogue spell is sustained, the magician can spend a Minor Action to visualize any element in the spell's area, from any angle.\nThe magician benefits from 1 Edge reroll on any Surprise test in the area or all attacks against invisible targets, because Catalogue gives them a variety of details that do not depend only on sight.\nlist of details\n• knows exactly the number of objects in a container or an area.\n• knows the dimensions of an object (height, width, length, volume, surface area).\n• knows the weight of an object to the nearest gram and whether the magician is able to lift or carry it.\n• knows the temperature of an object to the nearest degree.\n• knows the direction in which an object is facing in degrees.\n• knows the distance between objects to the nearest millimeter.\n• identifies the precise smell of individuals and objects and determines if someone whose smell they know has recently been in this area.\n• identifies the ingredients in dishes or drinks.\n• identifies textures as subtle as the imprints of writing on a sheet of paper, the precise shades of a color or brush strokes.\n• identifies musical tone by ear or by feeling the frequency of vibrations." },
  { id: "charisma", name: "Charisma", frenchName: "Charabia", category: "Illusion", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 14, description: "This spell is cast between the magician and a willing subject they touch. Several people can be connected to the same secret conversation; each additional person increases the Drain of the spell by 1.\nAny Perception test lower than the number of successes obtained when casting the spell only allows the interlocutor to hear a trivial conversation that has no relation to the real conversation.\nGibberish affects living entities.\nJibberish works just as well on cameras and other technological devices as on living entities." },
  { id: "catfall", name: "Catfall", frenchName: "Chute féline", category: "Manipulation", type: "Physical", drain: "3", range: "Self", duration: "Sustained", page: 18, description: "Each net success is equivalent to 3 additional meters of safe fall (cumulative), which are added to the 3 meters of safety that everyone benefits from (p. 114, SR6).\nThe subject also gains 1 Edge reroll for their Athletics + Agility test to cushion the fall.\nEach success increases the distance of fall without damage by 1 meter." },
  { id: "clairaudience", name: "Clairaudience", frenchName: "Clairaudience", category: "Detection", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 7, description: "The person on whom this spell is cast gains the ability to hear distant sounds. The subject can choose and move the area in which they listen; the dimension of this area is determined according to the normal rules for area effects and can be adjusted with Area Extension and moved with Area Displacement. The subject can only hear sounds in the targeted area while the spell is in effect (and not sounds near the area) and any hearing enhancement they might benefit from has no effect." },
  { id: "clairvoyance", name: "Clairvoyance", frenchName: "Clairvoyance", category: "Detection", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 8, description: "Like clairaudience, but for seeing instead of hearing, so the person on whom this spell is cast gains the ability to see at a distance. The subject can choose and move the area in which they observe; the dimension of this area is determined according to the normal rules for area effects and can be adjusted with Area Extension and moved with Area Displacement. The subject can only see in the targeted area while the spell is in effect (and not what is around the area) and any visual enhancement they might benefit from has no effect." },
  { id: "glue", name: "Glue", frenchName: "Colle", category: "Manipulation", type: "Physical", drain: "5", range: "LdV", duration: "Sustained", page: 18, description: "Glue targets two objects or subjects in contact at the time of casting. Objects resist with their Object Resistance (p. 3) and subjects with Reaction + Intuition, the highest dice pool between the two is used to resist the spell.\nIndividuals glued to a structure gain the Immobilized condition (p. 56, SR6) until they are freed.\nIf the spell succeeds, separating the two surfaces requires an opposed test between the net successes of the spell + the caster's Magic rating, and the Strength + Constitution of the person trying to separate them.\nIf the net successes of the Sorcery test exceed the Structure or Resistance of the object/subject, then the latter will suffer physical damage if they are separated, with a Damage Value equal to the net successes of the Sorcery test. They resist normally with their Structure or Constitution." },
  { id: "lokis-musical-comedy", name: "Loki's Musical Comedy", frenchName: "Comédie musicale de Loki", category: "Illusion", type: "Mana", drain: "5", range: "LOS", duration: "Sustained", page: 18, description: "The subjects in the area of effect of the spell can be willing or unwilling. Unwilling participants can resist the spell with Willpower + Magic.\nIf the spell succeeds, the subjects find themselves in a low-level psychic connection with each other and with the magician. Through this link, the subjects can hear music and benefit from mystical coordination for any physical action to be in rhythm with the music.\nWhile the spell is sustained, the magician must spend a Major Action per round to make a Con + Charisma (Performance) test for the choreography and a Minor Action to perform the action they are interested in. Each success on their Con test grants them one extra die for the main action, in addition to the dice gained by the targets' teamwork test.\nWilling subjects must spend a Major Action per round to make a Con + Charisma (Performance) test for the choreography and a Minor Action to assist the spellcaster in their main action. Each success on their Con test grants them one extra die for the teamwork test.\nUnwilling subjects who failed to resist the spell cannot voluntarily leave the area of effect of the spell. They must spend a Major Action per round to assist the spellcaster in their main action." },
  { id: "confusion", name: "Confusion", frenchName: "Confusion", category: "Illusion", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 14, description: "Confusion affects the target with a flood of images and emotions that leaves them disoriented and confused. Make a Sorcery + Magic test against Willpower + Logic: the target suffers the Confused condition (p. 55, SR6) with a rating equal to the net successes of the test. The target suffers a dice pool penalty equal to this rating for all their tests except damage resistance tests.\nImproved Confusion produces the same effect, but also affects cameras, microphones and other forms of technology.\nThe base spell affects only one individual, but the Area Extension effect can be used to turn it into an area spell (starting with a 2-meter radius for +1 Drain). When it is an area spell, the Area Displacement effect can be used." },
  { id: "superior-confusion", name: "Superior Confusion", frenchName: "Confusion supérieure", category: "Illusion", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 14, description: "Confusion affects the target with a flood of images and emotions that leaves them disoriented and confused. Make a Sorcery + Magic test against Willpower + Logic: the target suffers the Confused condition (p. 55, SR6) with a rating equal to the net successes of the test. The target suffers a dice pool penalty equal to this rating for all their tests except damage resistance tests.\nImproved Confusion produces the same effect, but also affects cameras, microphones and other forms of technology.\nThe base spell affects only one individual, but the Area Extension effect can be used to turn it into an area spell (starting with a 2-meter radius for +1 Drain). When it is an area spell, the Area Displacement effect can be used." },
  { id: "control-actions", name: "Control Actions", frenchName: "Contrôle des actes", category: "Manipulation", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 18, description: "The spellcaster acts like a true puppeteer and takes control of another person to make them dance according to their own will. Make a Sorcery + Magic test against Willpower + Logic.\nThe target is aware of what is happening, but can do nothing about it. To command them, the spellcaster uses the same type of action as the one they ask them to perform; so asking them to move is a Minor Action and asking them to attack is a Major Action.\nThis spell can be turned into an area spell with the Area Extension effect. Once the spell is cast, the effect affects individuals who did not resist even if they leave the initial area of effect." },
  { id: "control-thoughts", name: "Control Thoughts", frenchName: "Contrôle des pensées", category: "Manipulation", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 19, description: "Similar to Control Actions, but more insidious, this spell allows the caster to enter the target's head to impose their will. Make a Sorcery + Magic test against Willpower + Logic.\nUnlike Control Actions, it is not certain that the victim is aware that this spell is being used against them. The closer the caster's thoughts are to those of the victim, the less likely the latter is to notice the intrusion. At the GM's discretion, the victim may make a Logic + Intuition test after the spell ends to know if they can realize they were subjected to its effects; the threshold is then based on the difference between their normal thoughts and those they had while controlled.\nAlthough the spellcaster has a strong influence on the target's thoughts, some instincts are very difficult to neutralize. A victim will thus often resist thoughts such as \"I should jump from the top of this building\" or \"I should attack my best friend/spouse/partner.\" With such thoughts, the GM may decide that the victim makes another Willpower + Logic test to resist this type of suggestion and they can use Edge before the test if the thought is too foreign to their normal attitude or if it violates their basic instincts." },
  { id: "control-mob", name: "Control Mob", frenchName: "Contrôle des pensées des foules", category: "Manipulation", type: "Mana", drain: "5", range: "LOS", duration: "Sustained", page: 19, description: "The targets in the area of effect each resist the spell with Willpower + Logic.\nIf Control Thoughts of Crowds succeeds, for every 2 net successes, the targets change their attitude toward a subject chosen by the magician (including themselves) in the direction the magician wants them to take. There are four basic levels of attitudes: hostility, antipathy, neutrality and friendship. The caster can alter the attitude of the targets toward a specific subject, or more than one if they obtain enough net successes. This new attitude can affect the Social Edge (p. 50, SR6) while the spell is active.\nThe caster has no control over the actions taken by the subjects under the influence of this new mentality.\nIf they obtain more than 5 net successes, the caster can make a Con + Charisma test against Intuition + Willpower; if they succeed, the caster has created a group of extras (p. 118, SR6) that can cause a riot, a brawl, a demonstration, etc." },
  { id: "Couche de glace", name: "Couche de glace", frenchName: "Couche de glace", category: "Manipulation", type: "Physical", drain: "5", range: "LdV", duration: "Sustained", page: 18, description: "" },


  // ==================== D ====================
  { id: "decomposition", name: "Decomposition", frenchName: "Décomposition", category: "Manipulation", type: "Physical", drain: "5", range: "LOS", duration: "Sustained", page: 10, description: "Used offensively, Decomposition can cripple a subject. To cast this spell, make an opposed Sorcery + Magic test against Willpower + Intuition, or object resistance. The caster can inflict an additional level of the Crippled condition (up to level III; p. 102, Gun Fu) or Fatigued condition (up to level III; p. 56, SR6) for every two net successes, due to the breaking of the link between flesh and bones, which may even cease to exist. These conditions last until the target has been able to take at least one hour of rest.\nWhen not used offensively, this spell can affect 0.5 cubic meters of material. The Area Extension effect can be used with Decomposition to increase the volume by 0.5 cubic meters (up to half the caster's Magic rating in cubic meters, rounded up).\nFor bodies, consider that an increase in volume is necessary for trolls and potentially more for larger bodies." },
  { id: "ghost-decor", name: "Ghost Decor", frenchName: "Décor fantôme", category: "Illusion", type: "Mana", drain: "5", range: "LOS", duration: "Sustained", page: 15, description: "Vehicle Makeup does not modify the physical attributes of the vehicle.\nThe illusory objects of Ghost Decor are not meant to be crossed by physical objects, the spell cannot prevent them.\nVehicle Makeup affects a standard vehicle or drone; the Area Extension effect must be used once to mask an SUV, pickup or van type vehicle; twice for a van, shuttle or delivery truck; three times for a semi-trailer or bus. The illusion can be larger than the selected vehicle, but cannot be smaller.\nGhost Decor has a larger than normal area of effect, in the form of a cube rather than a sphere. It starts at 20 cubic meters (about the size of a small room) and increases by 20 cubic meters with each Area Extension effect. This only affects decor and inanimate objects, not objects that will be touched and used.\nFor these two spells, the magician's Sorcery + Magic test is opposed by the spectator's Willpower + Intuition.\nNeither affects technological devices." },
  { id: "deflagration", name: "Deflagration", frenchName: "Déflagration", category: "Combat", type: "Physical", drain: "4", range: "LOS", duration: "Instant", page: 6, description: "A very sneaky little spell; the magic does not touch the target, but acts on the air to deliver the blow. It is a true demonstration of the erosive power of wind applied to the target's head. Ranged Strike targets only one individual at a time while Deflagration is an area spell." },
  { id: "smash-object", name: "Smash Object", frenchName: "Défonçage (objet)", category: "Manipulation", type: "Physical", drain: "spécial", range: "Touch", duration: "Permanent", page: 3, description: "These spells must incorporate an object into the spell formula (firearm, commlink, armor, etc.). The chosen object can be precise or vague. See the table below for examples of objects that can be destroyed by these spells.\nThey can be learned multiple times by choosing a new object.\nYou gain 1 Edge point when casting the spell, if the object is precise rather than vague (e.g. heavy pistol instead of firearms).\nDirect area spells target all objects that match the criterion and are visible to the magician, unlike indirect spells which affect all objects in the area, visible or not.\nCorrosion, Fusion and Pulp are indirect combat spells (p. 4), which means that a targeted object belonging to someone cannot avoid the spell (p. 136, SR6). To cast these spells, you must make a Sorcery + Magic test against the Reaction + Willpower of the subject who controls the object (or Piloting + Evasion in the case of remotely controlled vehicles). The object will resist damage with its Structure rating (see effect table). They inflict chemical damage (p. 114, SR6) and subject the targets to the Corroded condition (p. 55, SR6) with a rating equal to the net successes on the Sorcery test.\nSmash, Dismantle and Demolish are direct combat spells (p. 3). To cast these spells, you must make a Sorcery + Magic test against the object's Resistance rating. It cannot resist damage." },
  { id: "clearance", name: "Clearance", frenchName: "Dégagement", category: "Health", type: "Mana", drain: "5", range: "Touch", duration: "Permanent", page: 11, description: "Slowed by magic, a creature or something else? Use Clearance and move forward! Touch someone suffering from the Restrained or Immobilized condition and make a Sorcery + Magic test with a difficulty threshold equal to the Magic rating of the being that imposed that condition, the Virulence of the toxin or the base damage value of the weapon that inflicted it (if more than one case applies, choose the highest value). For targets with the Immobilized or Restrained condition, the net successes serve as bonus dice for tests to resist the condition or ignore the pain that the condition might inflict." },
  { id: "dismantle-object", name: "Dismantle Object", frenchName: "Démantèlement (objet)", category: "Manipulation", type: "Physical", drain: "2", range: "Touch", duration: "Permanent", page: 3, description: "These spells must incorporate an object into the spell formula (firearm, commlink, armor, etc.). The chosen object can be precise or vague. See the table below for examples of objects that can be destroyed by these spells.\nThey can be learned multiple times by choosing a new object.\nYou gain 1 Edge point when casting the spell, if the object is precise rather than vague (e.g. heavy pistol instead of firearms).\nDirect area spells target all objects that match the criterion and are visible to the magician, unlike indirect spells which affect all objects in the area, visible or not.\nCorrosion, Fusion and Pulp are indirect combat spells (p. 4), which means that a targeted object belonging to someone cannot avoid the spell (p. 136, SR6). To cast these spells, you must make a Sorcery + Magic test against the Reaction + Willpower of the subject who controls the object (or Piloting + Evasion in the case of remotely controlled vehicles). The object will resist damage with its Structure rating (see effect table). They inflict chemical damage (p. 114, SR6) and subject the targets to the Corroded condition (p. 55, SR6) with a rating equal to the net successes on the Sorcery test.\nSmash, Dismantle and Demolish are direct combat spells (p. 3). To cast these spells, you must make a Sorcery + Magic test against the object's Resistance rating. It cannot resist damage." },
  { id: "demolish-object", name: "Demolish Object", frenchName: "Démolition (objet)", category: "Manipulation", type: "Physical", drain: "Special", range: "LOS (Z)", duration: "Permanent", page: 3, description: "These spells must incorporate an object into the spell formula (firearm, commlink, armor, etc.). The chosen object can be precise or vague. See the table below for examples of objects that can be destroyed by these spells.\nThey can be learned multiple times by choosing a new object.\nYou gain 1 Edge point when casting the spell, if the object is precise rather than vague (e.g. heavy pistol instead of firearms).\nDirect area spells target all objects that match the criterion and are visible to the magician, unlike indirect spells which affect all objects in the area, visible or not.\nCorrosion, Fusion and Pulp are indirect combat spells (p. 4), which means that a targeted object belonging to someone cannot avoid the spell (p. 136, SR6). To cast these spells, you must make a Sorcery + Magic test against the Reaction + Willpower of the subject who controls the object (or Piloting + Evasion in the case of remotely controlled vehicles). The object will resist damage with its Structure rating (see effect table). They inflict chemical damage (p. 114, SR6) and subject the targets to the Corroded condition (p. 55, SR6) with a rating equal to the net successes on the Sorcery test.\nSmash, Dismantle and Demolish are direct combat spells (p. 3). To cast these spells, you must make a Sorcery + Magic test against the object's Resistance rating. It cannot resist damage." },
  { id: "detect-magic", name: "Detect Magic", frenchName: "Détection de la magie", category: "Detection", type: "Mana", drain: "4", range: "LOS (Z)", duration: "Sustained", page: 8, description: "Nobody wants to rummage through an entire junkyard to find a magical ring among the trash, but sometimes you have to. That's why an enterprising mage developed this spell that alerts the caster as soon as it detects active magic within range of their senses. This includes foci, reagents, active spirits, runes, alchemical preparations, active spells, rituals, astral signatures, paracritters, triggered or depleted alchemical preparations or the effects of permanent spells once they have become permanent." },
  { id: "detect-life", name: "Detect Life", frenchName: "Détection de la vie", category: "Detection", type: "Mana", drain: "3", range: "LOS (Z)", duration: "Sustained", page: 8, description: "Are people hiding behind that pile of rubble? Or in this forest? This spell will tell you. Despite its name, it does not detect all forms of life, only conscious beings." },
  { id: "detect-enemies", name: "Detect Enemies", frenchName: "Détection des ennemis", category: "Detection", type: "Mana", drain: "4", range: "LOS (Z)", duration: "Sustained", page: 8, description: "This spell allows the subject to know if anyone within range of the spell has hostile intentions toward them. This spell only works on people, not things, and it only detects individuals whose hostility is directed against the subject, not those who have a generalized hatred for an entire population (if that were the case, the entire Barrens population would trigger the spell). Ideal for detecting ambushes!" },
  { id: "diagnosis", name: "Diagnosis", frenchName: "Diagnostic", category: "Health", type: "Mana", drain: "4", range: "Touch", duration: "Permanent", page: 11, description: "To cast this spell, make a Sorcery + Magic (5 — Essence) test, the diagnosis table indicates the result based on the number of successes. The results obtained are cumulative, up to the number of successes obtained on the roll. If the magician obtains 3 successes, they have access to the results for 1, 2 and 3 successes.\nOnce the Diagnosis spell has been cast on someone, it cannot be cast on the same person for twenty-four hours.\nUsing Diagnosis grants the magician 1 Edge reroll on the Biotech skill test, if it is used on the same subject within twenty-four hours." },
  { id: "attribute-drain", name: "Attribute Drain", frenchName: "Diminution d'attribut", category: "Manipulation", type: "Mana", drain: "3", range: "Touch", duration: "Sustained", page: 10, description: "The mage's touch weakens, slows or stuns the target, temporarily reducing one of its attributes (down to a minimum of 1). The spellcaster decides which attribute will be affected before using their spell. Then they make a Sorcery + Magic test against Willpower + targeted attribute. The mage can choose the number of net successes to use to reduce the attribute at a rate of 1 point of reduction per net success; for each net success used after the first, the spell's Drain is increased by 1 point. This spell cannot affect Edge, Essence, Magic or Resonance." },
  { id: "dispel-focus", name: "Dispel Focus", frenchName: "Dissipation (focus)", category: "Combat", type: "Mana", drain: "6", range: "LOS", duration: "Permanent", page: 5, description: "The formulas of these spells can be general (the spells will affect all foci) or specific to a precise type of focus (enchantment, metamagic, power, qi, spell, spirit or weapon).\nThe spell formulas are extremely specialized, to be able to act specifically on foci. Other spells affecting the astral or of the mana type cannot interact with foci in the same way as these spells; conversely, these spells cannot interact with other astral forms than foci.\nIf this spell is learned for a precise type of focus, you gain 1 Edge point when you cast it.\nThe specific versions can be learned more than once, by choosing a different type of focus each time." },
  { id: "telekinetic-fingers", name: "Telekinetic Fingers", frenchName: "Doigts télékinésiques", category: "Manipulation", type: "Physical", drain: "4", range: "LOS", duration: "Sustained", page: 19, description: "The Telekinetic Fingers spell does not replicate fine motor skills exactly. Do not try to repair a watch, operate on someone or defuse a bomb with Telekinetic Fingers.\nThe magician holds a pair of invisible hands, at most one meter apart from each other, with which they can perform several actions.\nWith a Minor Action, the hands can be placed anywhere in the magician's line of sight, as for an area displacement.\nWhen the hands attempt to do something, they use the appropriate skill rating of the caster combined with an attribute equal to the net successes obtained on the Sorcery test. If they move an object, they move at most (Magic) meters per round. The Strength, Constitution and Willpower (for Lift/Carry tests) of the hands are equal to the number of successes on the Sorcery test.\nThe mage cannot gain or spend Edge when performing an action with Telekinetic Fingers." },
  { id: "Double physique", name: "Double physique", frenchName: "Double physique", category: "Illusion", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 14, description: "" },


  // ==================== E ====================
  { id: "force-bolt", name: "Force Bolt", frenchName: "Éclair de force", category: "Combat", type: "Physical", drain: "5", range: "LOS", duration: "Instant", page: 5, description: "A more extreme version of ranged strike, Force Bolt inflicts physical damage on a target; Force Sphere does the same thing, but in an area." },
  { id: "stun-bolt", name: "Stun Bolt", frenchName: "Éclair étourdissant", category: "Combat", type: "Mana", drain: "5", range: "LOS", duration: "Instant", page: 5, description: "Sometimes you need to be a little more subtle. These spells channel mana in such a way as to stun their targets. Stun Bolt affects only one individual while Stun Sphere is an area spell." },
  { id: "mana-bolt", name: "Mana Bolt", frenchName: "Éclair mana", category: "Combat", type: "Mana", drain: "5", range: "LOS", duration: "Instant", page: 5, description: "An essential spell that allows shaping mana to break skulls. Who can deny the purity of this magic? Mana Bolt affects only one individual while Mana Sphere is an area spell." },
  { id: "borrow-sense", name: "Borrow Sense", frenchName: "Emprunt de sens", category: "Detection", type: "Mana", drain: "5", range: "LOS", duration: "Sustained", page: 8, description: "Borrow Sense and Animal Sense allow the magician to select one sense (sight, hearing, smell, taste) of the subject and, with a Minor Action, to feel it from the subject's point of view instead of their own.\nPassenger allows the magician to perceive all the subject's senses simultaneously, making it literally a live magical simsense experience (with the exception of emotional baggage).\nPack Eye is limited to sight.\nAnimal Sense only works on non-conscious animals (including paranormal animals).\nAny improvement (such as thermographic vision, low-light vision and high frequencies) linked to the subject's sense is included with the perception the magician benefits from, whatever the source of that improvement. The additional information the subject may benefit from thanks to another detection spell is not transmitted.\nAstral, virtual and augmented reality perception cannot be channeled through this spell.\nThe subject can resist Sense, Passenger and Animal Sense spells with Constitution + Willpower, but they are not aware of the moment the spell takes effect.\nPack Eye only acts on conscious subjects, conscious or not, including paracritters.\nIncrease the Drain by 1 for each subject connected in addition to the first (with a maximum number of subjects equal to the caster's Magic rating).\nWhen this spell is sustained, the caster can spend a Minor Action to change their point of view to that of another connected subject." },
  { id: "ephedrine", name: "Ephedrine", frenchName: "Éphédrine", category: "Health", type: "Mana", drain: "4", range: "Contact", duration: "Sustained", page: 10, description: "To cast Anaphylaxis, make an opposed Sorcery + Magic test against Constitution + Willpower. Casting Ephedrine is a simple Sorcery + Magic (5 — Essence) test. For every two net successes, the severity of the allergic reaction increases (Anaphylaxis) or decreases (Ephedrine) by one level (p. 76, SR6). The first two successes cause a mild severity allergic reaction (to the substance chosen by the magician at the time of casting) as long as the spell is sustained.\nWhen it is no longer used, the allergic reaction returns to a normal level or disappears if no active allergen is present." },
  { id: "infernal-explosion", name: "Infernal Explosion", frenchName: "Explosion infernale", category: "Combat", type: "Physical", drain: "8", range: "LOS (Z)", duration: "Instant", page: 7, description: "The side effects of flamethrower/fire bolt/fireball/infernal explosion can include igniting combustible materials, toxic aerosols and the attention of law enforcement.\nInfernal Explosion has the same damage potential as a Fireball, but can inflict the Corroded condition (p. 55, SR6), at a level equal to the number of net successes on the Sorcery test." },

  // ==================== F ====================
  { id: "fenetre-astrale", name: "Astral Window", frenchName: "Fenêtre astrale", category: "Detection", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 8, description: "XXX" },
  { id: "fenetre-mana", name: "Mana Window", frenchName: "Fenêtre mana", category: "Detection", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 8, description: "XXX" },
  { id: "fleau-cible", name: "Fleau", frenchName: "Fléau (cible)", category: "Combat", type: "Mana", drain: "3", range: "LOS", duration: "Instant", page: 7, description: "XXX" },
  { id: "flot-acide", name: "Acid Stream", frenchName: "Flot acide", category: "Combat", type: "Physical", drain: "5", range: "LOS", duration: "Instant", page: 5, description: "XXX" },
  { id: "frappe", name: "Strike", frenchName: "Frappe", category: "Combat", type: "Physical", drain: "4", range: "Touch", duration: "Instant", page: 5, description: "XXX" },
  { id: "frappe-distance", name: "Strike at Distance", frenchName: "Frappe à distance", category: "Combat", type: "Physical", drain: "5", range: "LOS", duration: "Instant", page: 6, description: "XXX" },
  { id: "fusion-objet", name: "Fusion", frenchName: "Fusion (objet)", category: "Manipulation", type: "Physical", drain: "3", range: "Touch", duration: "Permanent", page: 4, description: "These spells must incorporate an object into the spell formula (firearm, commlink, armor, etc.). The chosen object can be precise or vague. See the table below for examples of objects that can be destroyed by these spells.\nThey can be learned multiple times by choosing a new object.\nYou gain 1 Edge point when casting the spell, if the object is precise rather than vague (e.g. heavy pistol instead of firearms).\nDirect area spells target all objects that match the criterion and are visible to the magician, unlike indirect spells which affect all objects in the area, visible or not.\nCorrosion, Fusion and Pulp are indirect combat spells (p. 4), which means that a targeted object belonging to someone cannot avoid the spell (p. 136, SR6). To cast these spells, you must make a Sorcery + Magic test against the Reaction + Willpower of the subject who controls the object (or Piloting + Evasion in the case of remotely controlled vehicles). The object will resist damage with its Structure rating (see effect table). They inflict chemical damage (p. 114, SR6) and subject the targets to the Corroded condition (p. 55, SR6) with a rating equal to the net successes on the Sorcery test.\nSmash, Dismantle and Demolish are direct combat spells (p. 3). To cast these spells, you must make a Sorcery + Magic test against the object's Resistance rating. It cannot resist damage." },
  { id: "phantasm", name: "Phantasm", frenchName: "Fantasme", category: "Illusion", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 15, description: "Crée une illusion visuelle réaliste." },
  { id: "superior-phantasm", name: "Superior Phantasm", frenchName: "Fantasme supérieur", category: "Illusion", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 15, description: "Version améliorée et plus réaliste de Fantasme." },
  { id: "false-impression", name: "False Impression", frenchName: "Fausse impression", category: "Illusion", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 15, description: "Crée une fausse impression sensorielle chez la cible." },
  { id: "flamethrower", name: "Flamethrower", frenchName: "Foudre", category: "Combat", type: "Physical", drain: "5", range: "LdV", duration: "Instant", page: 5, description: "Projette un puissant jet de flammes." },

  // ==================== I ====================
  { id: "ectomagic-impulse", name: "Ectomagic Impulse", frenchName: "Impulsion ectomagique (focus)", category: "Combat", type: "Mana", drain: "7", range: "LOS", duration: "Instant", page: 5, description: "The formulas of these spells can be general (the spells will affect all foci) or specific to a precise type of focus (enchantment, metamagic, power, qi, spell, spirit or weapon).\nThe spell formulas are extremely specialized, to be able to act specifically on foci. Other spells affecting the astral or of the mana type cannot interact with foci in the same way as these spells; conversely, these spells cannot interact with other astral forms than foci.\nIf this spell is learned for a precise type of focus, you gain 1 Edge point when you cast it.\nThe specific versions can be learned more than once, by choosing a different type of focus each time." },
  { id: "indifference", name: "Indifference", frenchName: "Indifférence", category: "Illusion", type: "Mana", drain: "5", range: "LOS", duration: "Sustained", page: 19, description: "When a magician casts Indifference, they select a subject who will not be affected by the spell and who will be ignored by those who are. They can select additional subjects; each additional individual increases the Drain value by 1.\nThe spellcaster makes a Sorcery + Magic test; all targets in the area of effect of the spell (or who enter it while the spell is sustained) resist with Willpower + Intuition. Those who fail to resist the spell ignore most of the things happening around them; nothing seems to matter.\nA guard on duty, for example, might wave to the subjects or even instinctively show friendliness toward them, but will not prevent them from advancing.\nThe targets affected by the spell have difficulty remembering the details of the period during which they were under its influence. The number of net successes when casting the spell becomes the threshold for memory tests when they try to recall precise details (p. 106, SR6).\nThe spell can be broken by the targets if:\n• Someone tries to directly harm an affected person. The survival instinct automatically breaks the spell.\n• Someone crossing the area of effect of the spell obtains a complication or a critical failure on a test. They might do something strange and blatant enough that the targets cannot ignore it.\n• A sudden change in the environment (fire, shooting, fire and shooting, alarms) gives the targets a second chance to resist the spell. They benefit from 1 Edge reroll for this test.\n• Interfering with a target's work may allow them to retry resisting the spell. If runners try to open a door that the guard is trying to keep closed, or steal a car in a garage that a valet is watching, for example. The game master decides how much this disturbance justifies rerolling the dice." },
  { id: "Inquiétude", name: "Inquiétude", frenchName: "Inquiétude", category: "Illusion", type: "Mana", drain: "3", range: "LOS (Z)", duration: "Sustained", page: 19, description: "Bad Feeling affects animals, metahumans and conscious beings, while Anxiety only affects animals.\nBad Feeling mystically instills feelings of imminent danger, fear and unease in any living being that enters the area of effect of the spell.\nThe targets feel both frightened and nervous. Their hair stands on end and they feel slightly panicked.\nAny target that fails to resist the spell with Logic + Intuition gains the Frightened condition (p. 56, SR6) as long as they are in the area of effect of the spell.\nIf the net successes exceed the Willpower of the targeted individual, they gain the Panicked condition (p. 57, SR6) in addition to the Frightened condition and must leave the area.\nOnce outside the area of effect of the spell, the Frightened/Panicked conditions disappear in (caster's Magic rating) minutes." },
  { id: "inspection", name: "Inspection", frenchName: "Inspection", category: "Detection", type: "Mana", drain: "4", range: "Contact", duration: "Sustained", page: 9, description: "This spell allows the caster to be extremely focused on an object or an area. The Carefully Observe action becomes a Minor Action when the spell is sustained and used on the chosen object (Inspection) or area (Catalogue)." },
  { id: "invisibility", name: "Invisibility", frenchName: "Invisibilité", category: "Illusion", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 15, description: "The target is no longer visible and becomes transparent to go unnoticed. Invisibility grants the targeted character the Invisible condition (p. 57, SR6) and the rating becomes the threshold to reach for any test aimed at seeing this character. The Improved Invisibility spell grants the Invisible (Improved) condition which also works against cameras and other technological devices." },
  { id: "improved-invisibility", name: "Improved Invisibility", frenchName: "Invisibilité supérieure", category: "Illusion", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 15, description: "The target is no longer visible and becomes transparent to go unnoticed. Invisibility grants the targeted character the Invisible condition (p. 57, SR6) and the rating becomes the threshold to reach for any test aimed at seeing this character. The Improved Invisibility spell grants the Invisible (Improved) condition which also works against cameras and other technological devices." },

  // ==================== J ====================
  { id: "water-jet", name: "Water Jet", frenchName: "Jet d'eau", category: "Combat", type: "Physical", drain: "5", range: "LOS", duration: "Instant", page: 6, description: "The targets of the spell suffer the Soaked condition (p. 57, SR6).\nIf the spell succeeds, each target is pushed back one meter from the caster or the center of the spell.\nIf the net successes are greater than the Constitution of the target, the target suffers the Prone condition (p. 55, SR6). Each additional net success (which the target resists with a Constitution test) constitutes the number of meters the target will be pushed back, cumulative with the first meter." },
  { id: "fasting", name: "Fasting", frenchName: "Jeûne", category: "Health", type: "Mana", drain: "4", range: "Touch", duration: "Sustained", page: 12, description: "If cast successfully, this spell will remove all sensation of hunger or thirst from the subject for twenty-four hours. Each additional success reduces the level of the Fatigued condition caused by hunger and thirst by one level (see next page). Fasting does not replace the need for food and water." },
  { id: "jibberish", name: "Jibberish", frenchName: "Jobelin", category: "Illusion", type: "Mana", drain: "4", range: "Touch", duration: "Sustained", page: 14, description: "This spell is cast between the magician and a willing subject they touch. Several people can be connected to the same secret conversation; each additional person increases the Drain of the spell by 1.\nAny Perception test lower than the number of successes obtained when casting the spell only allows the interlocutor to hear a trivial conversation that has no relation to the real conversation.\nGibberish affects living entities.\nJibberish works just as well on cameras and other technological devices as on living entities." },

  // ==================== K ====================
  // (Aucune description complète trouvée pour les sorts commençant par K dans le document V8)

  // ==================== L ====================
  { id: "ice-lance", name: "Ice Lance", frenchName: "Lance de glace", category: "Combat", type: "Physical", drain: "5", range: "LOS", duration: "Instant", page: 6, description: "When all the corporate security agents you run into start wearing fireproof underwear, it's time to change things up a bit and use another extreme in the temperature domain. These spells affect their targets with freezing cold by inflicting Cold elemental damage (p. 114, SR6) and imposing the Chilled condition (p. 56, SR6) for a number of combat rounds equal to the net successes of the Spellcasting test. Ice Lance affects only one individual while Ice Storm is an area spell." },
  { id: "levitation", name: "Levitation", frenchName: "Lévitation", category: "Manipulation", type: "Physical", drain: "6", range: "LOS", duration: "Sustained", page: 19, description: "It's not quite the same as flying, but it's still quite a challenge to gravity. Make a Sorcery + Magic test; for each success, you can levitate up to 50 kilos of materials or individuals. In the latter case, if the person is not very enthusiastic about floating in the air, they can make a Constitution + Strength test and each success reduces yours by 1. The target must remain in your line of sight if you want them to stay in the air; the second you lose sight of them, they fall. This problem, as well as some caution when lifting someone into the air with a spell that can be interrupted, tends to limit the altitude at which you can send someone into the air with this spell.\nThe target does not have to remain hovering. It can be moved by the caster at a speed of (caster's Magic) meters per turn. Moving it requires a Minor Action." },
  { id: "mental-link", name: "Mental Link", frenchName: "Lien mental", category: "Detection", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 9, description: "Commlinks and SMS? That's the past. Projecting your thoughts into someone else's is the ultimate communication method! As soon as you get the first success on your Sorcery + Magic test, you establish a link and you can share mental communication with the subject of the spell in the form that seems most sensible to you. The spellcaster and the subject must remain within range of each other for the link to continue to function; if they move too far apart before returning within range, they can resume their communication as long as the spell has been sustained without interruption." },
  { id: "light", name: "Light", frenchName: "Lumière", category: "Manipulation", type: "Physical", drain: "3", range: "LOS (Z)", duration: "Sustained", page: 20, description: "These spells are the two sides of the same coin and allow you to modify the level of brightness of your environment as you wish. For each net success obtained, you can increase (with Light) or decrease (with Darkness) the level of brightness of the area around you, which can help you determine if you gain Edge based on the environment and visibility (p. 115, SR6). These are area spells and they can be adjusted with Area Extension and Area Displacement." },

  // ==================== M ====================
  { id: "crowd-manipulation", name: "Crowd Manipulation", frenchName: "Manipulation des foules", category: "Manipulation", type: "Mana", drain: "5", range: "LOS (Z)", duration: "Sustained", page: 20, description: "The targets in the area of effect each resist the spell with Willpower + Logic.\nIf Crowd Manipulation succeeds, the current feelings of the affected targets are replaced by a new emotional state (happy, angry, sad, etc.). The more successes you obtain, the more intense this new emotional state will be. It can disturb the subjects (apply a -1 dice pool penalty to tests involving active skills for every 2 net successes). Game masters can adapt the penalty to the situation, reducing it when actions are based on this new emotion, for example.\nThe caster has no control over the actions taken by the subjects under the influence of this new mentality.\nIf they obtain more than 5 net successes, the caster can make a Con + Charisma test against Intuition + Willpower; if they succeed, the caster has created a group of extras (p. 118, SR6) that can cause a riot, a brawl, a demonstration, etc." },
  { id: "makeup", name: "Makeup", frenchName: "Maquillage", category: "Illusion", type: "Physical", drain: "4", range: "Touch", duration: "Sustained", page: 20, description: "Makeup acts on a willing subject.\nMake a Sorcery test and consult the Makeup results table.\nMakeup can create a coating on certain surfaces, such as hair and nails, which will last for (Magic) hours on a living subject. It can only be cast once every twenty-four hours on the same subject. During this period, the coating will not flake, fade, or erase. At the end of the allotted time, it will disappear in the course of your daily routine.\nMakeup cannot heal any medical problem, but can cover it, if the magician obtains enough successes (2 or more).\nWhile the spell is active, the subject can gain 1 Edge point for their social tests thanks to their change in appearance." },
  { id: "vehicle-makeup", name: "Vehicle Makeup", frenchName: "Maquillage de véhicule", category: "Illusion", type: "Physical", drain: "4", range: "Touch", duration: "Sustained", page: 15, description: "Vehicle Makeup does not modify the physical attributes of the vehicle.\nThe illusory objects of Ghost Decor are not meant to be crossed by physical objects, the spell cannot prevent them.\nVehicle Makeup affects a standard vehicle or drone; the Area Extension effect must be used once to mask an SUV, pickup or van type vehicle; twice for a van, shuttle or delivery truck; three times for a semi-trailer or bus. The illusion can be larger than the selected vehicle, but cannot be smaller.\nGhost Decor has a larger than normal area of effect, in the form of a cube rather than a sphere. It starts at 20 cubic meters (about the size of a small room) and increases by 20 cubic meters with each Area Extension effect. This only affects decor and inanimate objects, not objects that will be touched and used.\nFor these two spells, the magician's Sorcery + Magic test is opposed by the spectator's Willpower + Intuition.\nNeither affects technological devices." },
  { id: "mask", name: "Mask", frenchName: "Masque", category: "Illusion", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 16, description: "Sometimes you don't want to be seen; other times you want to be taken for someone else. In the latter case, Mask is very useful. The spell modifies the critical characteristics of a person, their appearance, their smell, the sound of their voice and so on.\nMake a Sorcery + Magic test and note the number of successes obtained; these successes serve as the threshold when individuals try to see through this illusion which requires a Willpower + Intuition test. Mask only affects living beings while Improved Mask also affects cameras, microphones and other technological devices." },
  { id: "improved-mask", name: "Improved Mask", frenchName: "Masque supérieur", category: "Illusion", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 16, description: "Sometimes you don't want to be seen; other times you want to be taken for someone else. In the latter case, Mask is very useful. The spell modifies the critical characteristics of a person, their appearance, their smell, the sound of their voice and so on.\nMake a Sorcery + Magic test and note the number of successes obtained; these successes serve as the threshold when individuals try to see through this illusion which requires a Willpower + Intuition test. Mask only affects living beings while Improved Mask also affects cameras, microphones and other technological devices." },
  { id: "bad-feeling", name: "Bad Feeling", frenchName: "Mauvais pressentiment", category: "Illusion", type: "Mana", drain: "4", range: "LOS (Z)", duration: "Sustained", page: 19, description: "Bad Feeling affects animals, metahumans and conscious beings, while Anxiety only affects animals.\nBad Feeling mystically instills feelings of imminent danger, fear and unease in any living being that enters the area of effect of the spell.\nThe targets feel both frightened and nervous. Their hair stands on end and they feel slightly panicked.\nAny target that fails to resist the spell with Logic + Intuition gains the Frightened condition (p. 56, SR6) as long as they are in the area of effect of the spell.\nIf the net successes exceed the Willpower of the targeted individual, they gain the Panicked condition (p. 57, SR6) in addition to the Frightened condition and must leave the area.\nOnce outside the area of effect of the spell, the Frightened/Panicked conditions disappear in (caster's Magic rating) minutes." },
  { id: "fashion", name: "Fashion", frenchName: "Mode", category: "Manipulation", type: "Physical", drain: "4", range: "Touch", duration: "Permanent", page: 20, description: "The weight and volume of the fabric used for the garment cannot change. A jumpsuit cannot be turned into a bikini and vice versa. After making a Sorcery + Magic test against the Object Resistance rating + Defense Score of the garment or armor, consult the Fashion results table." },
  { id: "shape-stone", name: "Shape Stone", frenchName: "Modeler la pierre", category: "Manipulation", type: "Physical", drain: "4", range: "Touch", duration: "Sustained", page: 21, description: "These spells give you the ability to make the selected material malleable in order to shape it with your (mental) hands. You can shape the material as long as the spell is sustained; when the spell stops taking effect, the material retains the shape you gave it.\nMake a Sorcery + Magic test against Object Resistance; the amount of material you can shape is determined by the net successes of the test. You can shape 1 cubic meter of material per net success (see the Volume table p. 17 for more information). To be able to use this spell on an object, the latter does not need to be entirely made of the chosen material, but it must be the predominant material." },
  { id: "shape-wood", name: "Shape Wood", frenchName: "Modeler le bois", category: "Manipulation", type: "Physical", drain: "3", range: "Touch", duration: "Sustained", page: 21, description: "These spells give you the ability to make the selected material malleable in order to shape it with your (mental) hands. You can shape the material as long as the spell is sustained; when the spell stops taking effect, the material retains the shape you gave it.\nMake a Sorcery + Magic test against Object Resistance; the amount of material you can shape is determined by the net successes of the test. You can shape 1 cubic meter of material per net success (see the Volume table p. 17 for more information). To be able to use this spell on an object, the latter does not need to be entirely made of the chosen material, but it must be the predominant material." },
  { id: "shape-metal", name: "Shape Metal", frenchName: "Modeler le métal", category: "Manipulation", type: "Physical", drain: "5", range: "Touch", duration: "Sustained", page: 21, description: "These spells give you the ability to make the selected material malleable in order to shape it with your (mental) hands. You can shape the material as long as the spell is sustained; when the spell stops taking effect, the material retains the shape you gave it.\nMake a Sorcery + Magic test against Object Resistance; the amount of material you can shape is determined by the net successes of the test. You can shape 1 cubic meter of material per net success (see the Volume table p. 17 for more information). To be able to use this spell on an object, the latter does not need to be entirely made of the chosen material, but it must be the predominant material." },
  { id: "shape-plastic", name: "Shape Plastic", frenchName: "Modeler le plastique", category: "Manipulation", type: "Physical", drain: "2", range: "Touch", duration: "Sustained", page: 21, description: "These spells give you the ability to make the selected material malleable in order to shape it with your (mental) hands. You can shape the material as long as the spell is sustained; when the spell stops taking effect, the material retains the shape you gave it.\nMake a Sorcery + Magic test against Object Resistance; the amount of material you can shape is determined by the net successes of the test. You can shape 1 cubic meter of material per net success (see the Volume table p. 17 for more information). To be able to use this spell on an object, the latter does not need to be entirely made of the chosen material, but it must be the predominant material." },

  // ==================== N ====================
  { id: "napalm", name: "Napalm", frenchName: "Napalm", category: "Combat", type: "Physical", drain: "7", range: "LOS", duration: "Instant", page: 6, description: "Napalm inflicts the Burning condition (p. 56, SR6) at a level equal to the net successes on the Sorcery test.\nThe condition is inflicted even if the target benefits from fire resistance, but in this case the rating of the Burning condition is reduced by half. If the armor is also equipped with Chemical Protection (p. 275, SR6), Fire Resistance works normally.\nThe Area Extension effect can be used with Napalm, the area of effect going from one individual to a two-meter area (and beyond, if you really like the smell of napalm in the morning)." },
  { id: "cozy-nest", name: "Cozy Nest", frenchName: "Nid douillet", category: "Manipulation", type: "Physical", drain: "5", range: "LOS", duration: "Sustained", page: 11, description: "Neither rain, nor snow, nor hail will deter shadowrunners from their task! This spell keeps you dry and warm, even when you have to stay outside in freezing temperatures or under torrential rain. The drops sliding off you, you could even bathe in a few seconds. This spell cancels the Soaked and Chilled conditions of the subject and prevents them." },
  { id: "nutrition", name: "Nutrition", frenchName: "Nutrition", category: "Health", type: "Mana", drain: "4", range: "Touch", duration: "Permanent", page: 12, description: "Each success prevents famine and dehydration for twelve hours (with a maximum of 3 days), but does not remove the sensation of hunger or thirst (see the Fasting spell above).\nOn a subject already starving, each success reduces the level of the Fatigued condition, if it is linked to deprivation (Fasting, above, for more information on food and fatigue), before applying the successes intended to provide them with food." },

  // ==================== O ====================
  { id: "overclock", name: "Overclock", frenchName: "Overclock", category: "Manipulation", type: "Physical", drain: "4", range: "Touch", duration: "Sustained", page: 21, description: "Magic rarely marries well with technology, but sometimes a way is found to combine the two.\nWith this spell, a mage can briefly amplify the power of an electronic device so that it works better and faster. Make a Sorcery + Magic test against Object Resistance. For each net success, you can increase one attribute of the device (Device Rating, Attack, Data Processing, Firewall or Corruption) by 1 point. The caster can decide not to use all the net successes if they want to spare the device.\nThis use of magic puts the device under severe strain. Once the spell ends, the device suffers matrix damage equal to the net successes used, which it resists with Firewall." },
  { id: "oxygenation", name: "Oxygenation", frenchName: "Oxygénation", category: "Health", type: "Mana", drain: "4", range: "Touch", duration: "Sustained", page: 12, description: "Oxygenation requires the subject to be willing. To cast this spell, make a Sorcery + Magic (5 — Essence) test. Oxygenation offers 1 Edge reroll on the next Swimming or Diving test.\nEach net success gives you one extra die for damage resistance tests linked to asphyxiation, strangulation or any other form of oxygen loss.\nEach net success reduces the Fatigued or Dazed condition by one level, if the latter is caused by oxygen loss. While the spell is sustained, the subject is immune to inhalation vector attacks, as well as drowning (if the subject does not forget to hold their breath).\nExcessive use of Oxygenation can cause lung atrophy. If the spell is used every day for a week or more, assign the subject the Fatigued I condition, until they stop using it for the same number of days." },
  { id: "pack-eye", name: "Pack Eye", frenchName: "Œil de la meute", category: "Detection", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 8, description: "Borrow Sense and Animal Sense allow the magician to select one sense (sight, hearing, smell, taste) of the subject and, with a Minor Action, to feel it from the subject's point of view instead of their own.\nPassenger allows the magician to perceive all the subject's senses simultaneously, making it literally a live magical simsense experience (with the exception of emotional baggage).\nPack Eye is limited to sight.\nAnimal Sense only works on non-conscious animals (including paranormal animals).\nAny improvement (such as thermographic vision, low-light vision and high frequencies) linked to the subject's sense is included with the perception the magician benefits from, whatever the source of that improvement. The additional information the subject may benefit from thanks to another detection spell is not transmitted.\nAstral, virtual and augmented reality perception cannot be channeled through this spell.\nThe subject can resist Sense, Passenger and Animal Sense spells with Constitution + Willpower, but they are not aware of the moment the spell takes effect.\nPack Eye only acts on conscious subjects, conscious or not, including paracritters.\nIncrease the Drain by 1 for each subject connected in addition to the first (with a maximum number of subjects equal to the caster's Magic rating).\nWhen this spell is sustained, the caster can spend a Minor Action to change their point of view to that of another connected subject." },

  // ==================== P ====================
  { id: "Panomana", name: "Panomana", frenchName: "Panomana", category: "Illusion", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 15, description: "These spells cannot create a false aura, they can only modify or hide an existing aura.\nIf the magician obtains more successes on their spell than any other individual has on their Astral Observation, Astral Perception or Astral Window spell test, then they impose what they want to be seen.\nIf the result of the Astral or Sorcery test is higher than that of the False Impression/Panorama spell, then the individual recognizes that a concealment spell is being used, but they can only obtain the true information based on the difference between their successes and those of the False Impression/Panorama spell." },
  { id: "passenger", name: "Passenger", frenchName: "Passager", category: "Detection", type: "Mana", drain: "6", range: "LOS", duration: "Sustained", page: 8, description: "Borrow Sense and Animal Sense allow the magician to select one sense (sight, hearing, smell, taste) of the subject and, with a Minor Action, to feel it from the subject's point of view instead of their own.\nPassenger allows the magician to perceive all the subject's senses simultaneously, making it literally a live magical simsense experience (with the exception of emotional baggage).\nPack Eye is limited to sight.\nAnimal Sense only works on non-conscious animals (including paranormal animals).\nAny improvement (such as thermographic vision, low-light vision and high frequencies) linked to the subject's sense is included with the perception the magician benefits from, whatever the source of that improvement. The additional information the subject may benefit from thanks to another detection spell is not transmitted.\nAstral, virtual and augmented reality perception cannot be channeled through this spell.\nThe subject can resist Sense, Passenger and Animal Sense spells with Constitution + Willpower, but they are not aware of the moment the spell takes effect.\nPack Eye only acts on conscious subjects, conscious or not, including paracritters.\nIncrease the Drain by 1 for each subject connected in addition to the first (with a maximum number of subjects equal to the caster's Magic rating).\nWhen this spell is sustained, the caster can spend a Minor Action to change their point of view to that of another connected subject." },
  { id: "hot-potato", name: "Hot Potato", frenchName: "Patate chaude", category: "Illusion", type: "Mana", drain: "3", range: "LOS", duration: "Instant", page: 16, description: "The magician makes a Sorcery + Willpower test against Willpower + Intuition. If the target fails to resist the illusion, they are convinced that this object hurts them, their first reaction will thus be to drop everything they have in their hands. In combat, this means that their next action is Drop an Object (Minor Action)." },
  { id: "stone-fists", name: "Stone Fists", frenchName: "Poings de pierre", category: "Manipulation", type: "Physical", drain: "5", range: "Touch", duration: "Sustained", page: 21, description: "When casting this spell, the target's fists become hard as stone, which will give their opponent the impression of taking real cinder blocks! The target's unarmed melee Damage Value becomes 3P, modified normally according to Strength. In addition, the Offensive Score of the unarmed melee attack is increased by 1 per success on the Spellcasting test." },
  { id: "preservation", name: "Preservation", frenchName: "Préservation", category: "Health", type: "Mana", drain: "5", range: "Touch", duration: "Sustained", page: 12, description: "The ice will remain frozen, the pizza hot, usable materials and corpses in the state in which they were discovered, which will blur the estimates of the time of death.\nIf cast successfully, this spell prevents organic materials from decomposing naturally and from molding.\nEach success interrupts the evolution of the material for six hours after the spell was cast and keeps the temperature, humidity rate and so on, at the same level as they were when the spell was cast.\nThe spell acts on 1 cubic meter of material. The Area Extension effect can increase the volume by 0.5 cubic meters (up to half the caster's Magic rating in cubic meters, rounded up).\nEach success also counts as a protection rating against the Chilled, Burning or Corroded conditions, and grants spell resistance against decomposition.\nThe spell does not protect against physical damage." },
  { id: "projectile", name: "Projectile", frenchName: "Projectile", category: "Combat", type: "Physical", drain: "5", range: "LOS", duration: "Instant", page: 21, description: "If you have ever thought, \"If I had magical powers, I would catapult objects into the sky, but without a catapult,\" then this spell is for you. Make a Sorcery + Magic test against Object Resistance.\nFor each net success, you can project half a kilo of material into the air and the net successes also determine the threshold of a Reaction + Intuition test that targets must make to avoid this object. The projected objects have the following Offensive Scores: Close (Magic), Short: (Magic + 2), Medium (Magic + 1), Long: (Magic - 2), Extreme: —, and they inflict stun damage equal to their weight in kilos, rounded up." },

  // ==================== R ====================
  { id: "wall-reinforcement", name: "Wall Reinforcement", frenchName: "Renfort de mur", category: "Manipulation", type: "Physical", drain: "4", range: "LOS", duration: "Sustained", page: 21, description: "Whether you are trying to consolidate a wall that your opponents are trying to break or you want to isolate it so you no longer hear the people on the other side, strengthening an existing wall can be useful. Make a Sorcery + Magic test against Object Resistance for the wall you are trying to affect; the Structure rating is increased by 1 point per net success. With the base version of this spell you can affect a surface of four square meters; by using Area Extension, you increase this surface by four square meters each time you increase the Drain by 1 point. The Area Displacement adjustment can be used with this spell." },
  { id: "gecko-crawling", name: "Gecko Crawling", frenchName: "Reptation du gecko", category: "Manipulation", type: "Physical", drain: "4", range: "Self", duration: "Sustained", page: 21, description: "While this spell is sustained, the character is considered to have climbing gear and the base threshold of Climbing tests is reduced to 0 (see p. 100, SR6).\nThe subject can move on the ceiling at their normal climbing speed (provided the ceiling supports their weight). If the Structure rating (p. 116, SR6) is lower than the subject's Constitution, then the ceiling buckles or collapses under the subject's weight and Gecko Crawling fails to keep them attached." },
  { id: "pain-resistance", name: "Pain Resistance", frenchName: "Résistance à la douleur", category: "Health", type: "Mana", drain: "3", range: "Touch", duration: "Sustained", page: 12, description: "Although it does not allow healing, this spell allows the target to ignore the effects of damage and continue as if they were not suffering. The spellcaster makes a Sorcery + Magic (5 - Essence) test, which provides an automatic success if the target has an Essence of 6; for each net success, the target reduces by 1 the penalty to their dice pool due to damage." },
  { id: "dreams", name: "Dreams", frenchName: "Rêves", category: "Manipulation", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 22, description: "The target must be asleep or unconscious for the spell to work, but they can resist it with Willpower + Logic.\nDreams allows the magician to create a dream (including images, sound, emotions, etc.) and transmit it to a sleeping target. The net successes determine its complexity and details.\nDreams causes no real damage to the target.\nThe subject will remember the dream particularly well, but not necessarily that it was implanted.\nTo use this spell more aggressively, if the spellcaster obtains 5 net successes, they can disturb the subject's rest with a terrible nightmare for an entire day, preventing any attempt at natural recovery (p. 125, SR6). This means that no test can be made that day to heal physical damage." },
  { id: "rosier", name: "Rosier", frenchName: "Rosier", category: "Manipulation", type: "Physical", drain: "5", range: "LOS (Z)", duration: "Sustained", page: 22, description: "Successes accelerate plant growth. Each success corresponds to one week of growth or healing of damage boxes inflicted on the plant (if it has a condition monitor).\nUsing the Rosier spell offensively, any subject who crosses the area gains the Off-Balance condition (p. 102, Gun Fu), while enormous vegetation bursts forth (grasses, vines, branches, whatever comes to mind) and restricts all movement in the area. If the successes on the Sorcery test exceed the subject's Strength, then the subject also suffers the Restrained condition (p. 56, SR6) when moving through this area.\nThe plants are not animated after the initial spell casting. They have Strength and Constitution equal to half the caster's Magic attribute, rounded up. Constitution is used to calculate the condition monitor normally. To escape them, use the grappling rules with a dice pool equal to the caster's Magic attribute for the plants." },

  // ==================== S ====================
  { id: "animal-sense", name: "Animal Sense", frenchName: "Sens animal", category: "Detection", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 8, description: "Borrow Sense and Animal Sense allow the magician to select one sense (sight, hearing, smell, taste) of the subject and, with a Minor Action, to feel it from the subject's point of view instead of their own.\nPassenger allows the magician to perceive all the subject's senses simultaneously, making it literally a live magical simsense experience (with the exception of emotional baggage).\nPack Eye is limited to sight.\nAnimal Sense only works on non-conscious animals (including paranormal animals).\nAny improvement (such as thermographic vision, low-light vision and high frequencies) linked to the subject's sense is included with the perception the magician benefits from, whatever the source of that improvement. The additional information the subject may benefit from thanks to another detection spell is not transmitted.\nAstral, virtual and augmented reality perception cannot be channeled through this spell.\nThe subject can resist Sense, Passenger and Animal Sense spells with Constitution + Willpower, but they are not aware of the moment the spell takes effect.\nPack Eye only acts on conscious subjects, conscious or not, including paracritters.\nIncrease the Drain by 1 for each subject connected in addition to the first (with a maximum number of subjects equal to the caster's Magic rating).\nWhen this spell is sustained, the caster can spend a Minor Action to change their point of view to that of another connected subject." },
  { id: "combat-sense", name: "Combat Sense", frenchName: "Sens du combat", category: "Detection", type: "Mana", drain: "5", range: "LOS", duration: "Sustained", page: 9, description: "The subject has a greater perception of possible dangers and can react to them more quickly. The net successes of the Spellcasting tests are added to defense pools and for Surprise tests (see p. 112, SR6) as long as the spell is sustained." },
  { id: "silence", name: "Silence", frenchName: "Silence", category: "Illusion", type: "Mana", drain: "3", range: "LOS", duration: "Sustained", page: 16, description: "The target is subjected to silence and cannot make the slightest noise even if they want to. This can be ideal for individuals trying not to be noticed or a good way to sow confusion among people who are talking. Silence imposes the Silent condition (see p. 57, SR6) on the target with a rating equal to the net successes obtained on the Sorcery + Magic test. This rating acts as a threshold for any attempt to hear the character.\nImproved Silence has the same effect, but it imposes the Silent (Improved) condition and microphones and other technological systems cannot hear the character." },
  { id: "improved-silence", name: "Improved Silence", frenchName: "Silence supérieur", category: "Illusion", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 16, description: "The target is subjected to silence and cannot make the slightest noise even if they want to. This can be ideal for individuals trying not to be noticed or a good way to sow confusion among people who are talking. Silence imposes the Silent condition (see p. 57, SR6) on the target with a rating equal to the net successes obtained on the Sorcery + Magic test. This rating acts as a threshold for any attempt to hear the character.\nImproved Silence has the same effect, but it imposes the Silent (Improved) condition and microphones and other technological systems cannot hear the character." },
  { id: "healing", name: "Healing", frenchName: "Soins", category: "Health", type: "Mana", drain: "3", range: "Touch", duration: "Permanent", page: 12, description: "A run often comes with bumps, bruises and gunshot wounds and magic is perhaps the fastest and most effective method to heal them. When casting this spell, you must make a Sorcery + Magic (5 - Essence) test, which therefore provides an automatic success if the target has an Essence of 6. It allows recovering 1 damage box of your choice (stun, physical or overflow) per net success. Injuries can only be treated once by a Health spell (including Purifying Healing, Warming Healing and Cooling Healing).\nPurifying Healing eliminates the Corroded condition the patient might be suffering from.\nWarming Healing eliminates the Chilled condition the patient might be suffering from.\nCooling Healing eliminates the Burning condition the patient might be suffering from.\nInjuries can only be treated once by a Health spell (including Purifying Healing, Warming Healing and Cooling Healing)." },
  { id: "purifying-healing", name: "Purifying Healing", frenchName: "Soins purificateurs", category: "Health", type: "Mana", drain: "5", range: "Touch", duration: "Permanent", page: 12, description: "A run often comes with bumps, bruises and gunshot wounds and magic is perhaps the fastest and most effective method to heal them. When casting this spell, you must make a Sorcery + Magic (5 - Essence) test, which therefore provides an automatic success if the target has an Essence of 6. It allows recovering 1 damage box of your choice (stun, physical or overflow) per net success. Injuries can only be treated once by a Health spell (including Purifying Healing, Warming Healing and Cooling Healing).\nPurifying Healing eliminates the Corroded condition the patient might be suffering from.\nWarming Healing eliminates the Chilled condition the patient might be suffering from.\nCooling Healing eliminates the Burning condition the patient might be suffering from.\nInjuries can only be treated once by a Health spell (including Purifying Healing, Warming Healing and Cooling Healing)." },
  { id: "warming-healing", name: "Warming Healing", frenchName: "Soins réchauffants", category: "Health", type: "Mana", drain: "5", range: "Touch", duration: "Permanent", page: 12, description: "A run often comes with bumps, bruises and gunshot wounds and magic is perhaps the fastest and most effective method to heal them. When casting this spell, you must make a Sorcery + Magic (5 - Essence) test, which therefore provides an automatic success if the target has an Essence of 6. It allows recovering 1 damage box of your choice (stun, physical or overflow) per net success. Injuries can only be treated once by a Health spell (including Purifying Healing, Warming Healing and Cooling Healing).\nPurifying Healing eliminates the Corroded condition the patient might be suffering from.\nWarming Healing eliminates the Chilled condition the patient might be suffering from.\nCooling Healing eliminates the Burning condition the patient might be suffering from.\nInjuries can only be treated once by a Health spell (including Purifying Healing, Warming Healing and Cooling Healing)." },
  { id: "cooling-healing", name: "Cooling Healing", frenchName: "Soins refroidissants", category: "Health", type: "Mana", drain: "5", range: "Touch", duration: "Permanent", page: 12, description: "A run often comes with bumps, bruises and gunshot wounds and magic is perhaps the fastest and most effective method to heal them. When casting this spell, you must make a Sorcery + Magic (5 - Essence) test, which therefore provides an automatic success if the target has an Essence of 6. It allows recovering 1 damage box of your choice (stun, physical or overflow) per net success. Injuries can only be treated once by a Health spell (including Purifying Healing, Warming Healing and Cooling Healing).\nPurifying Healing eliminates the Corroded condition the patient might be suffering from.\nWarming Healing eliminates the Chilled condition the patient might be suffering from.\nCooling Healing eliminates the Burning condition the patient might be suffering from.\nInjuries can only be treated once by a Health spell (including Purifying Healing, Warming Healing and Cooling Healing)." },
  { id: "mind-probe", name: "Mind Probe", frenchName: "Sonde mentale", category: "Detection", type: "Mana", drain: "5", range: "LOS", duration: "Sustained", page: 9, description: "The subject of this spell can penetrate the mind of a target, perceive their thoughts while sorting between the truth and what they imagine. Make a Sorcery + Magic test against Willpower + Logic; the net successes determine the information that can be extracted from the target's head. The Mind Probe table indicates the type of information that can be obtained from the target if they are within range (determined normally).\nnet successes    result\n1-2              the subject can only read the target's surface thoughts.\n3-4              the subject can discover everything the target knows consciously and can see their recent thoughts (up to 72 hours).\n5+               the subject can explore the target's unconscious and obtain information the target may not be aware of, such as psychological problems, deep fears or hidden memories." },
  { id: "force-sphere", name: "Force Sphere", frenchName: "Sphère de force", category: "Combat", type: "Physical", drain: "5", range: "LOS (Z)", duration: "Instant", page: 5, description: "A more extreme version of ranged strike, Force Bolt inflicts physical damage on a target; Force Sphere does the same thing, but in an area." },
  { id: "lightning-sphere", name: "Lightning Sphere", frenchName: "Sphère de foudre", category: "Combat", type: "Physical", drain: "6", range: "LOS (Z)", duration: "Instant", page: 5, description: "This is what deities like Zeus or Thor used to punish those who aroused their wrath, which means it should suit you perfectly. Lightning Bolt affects only one target while Lightning Sphere is an area spell. Both spells inflict electrical elemental damage (p. 114, SR6), imposing the Electrocuted condition (p. 56, SR6) for a number of combat rounds equal to the net successes of the Spellcasting test." },
  { id: "stun-sphere", name: "Stun Sphere", frenchName: "Sphère étourdissante", category: "Combat", type: "Mana", drain: "4", range: "LOS (Z)", duration: "Instant", page: 5, description: "Sometimes you need to be a little more subtle. These spells channel mana in such a way as to stun their targets. Stun Bolt affects only one individual while Stun Sphere is an area spell." },
  { id: "mana-sphere", name: "Mana Sphere", frenchName: "Sphère mana", category: "Combat", type: "Mana", drain: "5", range: "LOS (Z)", duration: "Instant", page: 5, description: "An essential spell that allows shaping mana to break skulls. Who can deny the purity of this magic? Mana Bolt affects only one individual while Mana Sphere is an area spell." },
  { id: "Surcharge de focus", name: "Surcharge de focus", frenchName: "Surcharge de focus", category: "Manipulation", type: "Mana", drain: "7", range: "LOS (Z)", duration: "Limited", page: 22, description: "" },


  // ==================== T ====================
  { id: "radiant-complexion", name: "Radiant Complexion", frenchName: "Teint radieux", category: "Health", type: "Mana", drain: "4", range: "Touch", duration: "Sustained", page: 13, description: "To cast this spell, make a Sorcery + Magic (5 — Essence) test; if you succeed, the subject will appear much more well-groomed and in better health for up to one hour per net success, although external aggressions may reduce its effects. This means they obtain 1 Edge reroll on their social tests thanks to their appearance.\nIn addition, if you manage to cast this spell, any character who performs a First Aid or Healing test on the subject will benefit from 1 Edge reroll on the latter. This bonus effect is only temporary, it lasts (net successes) hours after the spell was cast. The spell can only be used once every twenty-four hours on the same subject." },
  { id: "ice-storm", name: "Ice Storm", frenchName: "Tempête de glace", category: "Combat", type: "Physical", drain: "6", range: "LOS (Z)", duration: "Instant", page: 6, description: "When all the corporate security agents you run into start wearing fireproof underwear, it's time to change things up a bit and use another extreme in the temperature domain. These spells affect their targets with freezing cold by inflicting Cold elemental damage (p. 114, SR6) and imposing the Chilled condition (p. 56, SR6) for a number of combat rounds equal to the net successes of the Spellcasting test. Ice Lance affects only one individual while Ice Storm is an area spell." },
  { id: "darkness", name: "Darkness", frenchName: "Ténèbres", category: "Manipulation", type: "Physical", drain: "3", range: "LOS (Z)", duration: "Sustained", page: 20, description: "These spells are the two sides of the same coin and allow you to modify the level of brightness of your environment as you wish. For each net success obtained, you can increase (with Light) or decrease (with Darkness) the level of brightness of the area around you, which can help you determine if you gain Edge based on the environment and visibility (p. 115, SR6). These are area spells and they can be adjusted with Area Extension and Area Displacement." },
  { id: "thunder", name: "Thunder", frenchName: "Tonnerre", category: "Combat", type: "Physical", drain: "3", range: "LOS (Z)", duration: "Sustained", page: 22, description: "A very loud distraction can always be useful. When casting this spell, the mage affects sound waves to generate the noise of their choice, whether it is a thunderclap, the noise of vehicles at rush hour or distant voices shouting, etc. The base area affected by the spell is a sphere with a two-meter radius; it can be extended by the Area Extension effect. For each success obtained on a Sorcery + Magic test, the noise continues for 1 combat round after the caster no longer concentrates on their spell. The net successes serve as a dice pool penalty for those who try to hear other sounds in the affected area." },
  { id: "death-touch", name: "Death Touch", frenchName: "Toucher mortel", category: "Combat", type: "Mana", drain: "3", range: "Touch", duration: "Instant", page: 6, description: "An essential spell that allows shaping mana to break skulls. Who can deny the purity of this magic? Mana Bolt affects only one individual while Mana Sphere is an area spell." },
  { id: "translation", name: "Translation", frenchName: "Traduction", category: "Detection", type: "Mana", drain: "4", range: "LOS", duration: "Sustained", page: 10, description: "Translation creates a slight telepathic connection between the subject and a precise target that their senses can perceive (see p. 135, SR6). An unwilling target can resist it with Constitution + Willpower.\nTranslation is useful for everyday conversations, not for diplomatic negotiations. If you use Translation, you cannot gain or spend Edge on social skill tests.\ntranslation quality\nsuccesses    conversation quality\n0            it's like shouting in front of a trideo. Yelling doesn't change anything.\n1            they are happy to see us this noon, be happy to have us as a deductor. It's a deduction based mainly on emotional context, with a word or two to make things more interesting.\n2            me want eat, dick. eat, dick, eat. A rudimentary conversation with kindergarten vocabulary.\n3            credstick. nuyen. firearms. The recurring conversation elements in the Sixth World. Nothing too technical.\n4+           someone wants to talk about nuclear physics? You can discuss more complex concepts with varied vocabulary." },
  { id: "fire-bolt", name: "Fire Bolt", frenchName: "Trait de feu", category: "Combat", type: "Physical", drain: "5", range: "LOS", duration: "Instant", page: 6, description: "A classic. When you think of hurting people with magic, the first thing that comes to mind is using fire. These are the spells that can allow you to do that. Fire Bolt affects only one individual at a time while Fire Sphere is an area spell. Both spells inflict Fire elemental damage (p. 114, SR6) and impose the Burning condition (p. 56, SR6) with a rating equal to the net successes obtained on the Spellcasting test." },
  { id: "treatment", name: "Treatment", frenchName: "Traitement", category: "Health", type: "Mana", drain: "4", range: "Touch", duration: "Permanent", page: 13, description: "Treatment cancels or reduces damage and the effects of debilitating conditions.\nTo cast this spell, make a Sorcery + Magic (5 — Essence) test. Reduce the Blinded, Burning, Corroded or Deafened condition by one level per net success or simply remove the Chilled or Dazed effect.\nIf the subject suffers from multiple conditions, the net successes can be divided and distributed among them, but each additional condition removed or reduced will increase the Drain by 1 point.\nSince each condition inflicts different effects, the game master can determine if Treatment can remove or reduce a particular condition. For example, Treatment obviously cannot help a subject with the Immobilized condition if they are tied to a bed, but the game master may allow the use of Treatment against the Immobilized condition if the subject obtained it by falling from a great height or by being poisoned, for example." },
  { id: "transparency", name: "Transparency", frenchName: "Transparence", category: "Manipulation", type: "Physical", drain: "Special", range: "Touch", duration: "Sustained", page: 22, description: "Transparent aluminum? Why not transparent concrete? To cast Transparency, make an opposed Sorcery + Magic test against the object's Resistance rating (p. 3). The spell affects 0.5 cubic meters per net success (see p. 17 for volume indications).\nThe Drain is equal to half the Structure rating (p. 116, SR6) of the object, rounded up (minimum 2). Any object affected by Transparency allows the magician to have a line of sight on objects or people on the other side of that object.\nTransparency provides no lighting, only transparency." },
  { id: "tsunami", name: "Tsunami", frenchName: "Tsunami", category: "Combat", type: "Physical", drain: "6", range: "LOS (Z)", duration: "Instant", page: 6, description: "The targets of the spell suffer the Soaked condition (p. 57, SR6).\nIf the spell succeeds, each target is pushed back one meter from the caster or the center of the spell.\nIf the net successes are greater than the Constitution of the target, the target suffers the Prone condition (p. 55, SR6). Each additional net success (which the target resists with a Constitution test) constitutes the number of meters the target will be pushed back, cumulative with the first meter." },

  // ==================== V ====================
  { id: "toxic-wave", name: "Toxic Wave", frenchName: "Vague toxique", category: "Combat", type: "Physical", drain: "6", range: "LOS (Z)", duration: "Instant", page: 4, description: "These spells project acid on their targets, inflicting immediate damage as well as chemical damage (p. 114, SR6) and subjecting the targets to the Corroded condition (p. 55, SR6) with a rating equal to the net successes of the Spellcasting test. Acid Bolt affects only one target while Toxic Wave is an area spell." },
  { id: "frozen-veins", name: "Frozen Veins", frenchName: "Veines gelées", category: "Manipulation", type: "Physical", drain: "4", range: "Touch", duration: "Sustained", page: 22, description: "Must target a willing subject. To cast this spell, make a Sorcery + Magic (5 — Essence) test.\nThe target suffers the Chilled condition (p. 56, SR6) and resists the Burning condition (p. 56, SR6) with a number of successes equal to the net successes of the Sorcery test.\nThe target does not appear on thermal sensors. This removes the environmental advantage of the attacker or defender on the subject, if it is based on thermal vision." },
  { id: "vine", name: "Vine", frenchName: "Vigne", category: "Manipulation", type: "Physical", drain: "4", range: "LOS (Z)", duration: "Sustained", page: 22, description: "Successes accelerate plant growth. Each success corresponds to one week of growth or healing of damage boxes inflicted on the plant (if it has a condition monitor).\nUsing the Rosier spell offensively, any subject who crosses the area gains the Off-Balance condition (p. 102, Gun Fu), while enormous vegetation bursts forth (grasses, vines, branches, whatever comes to mind) and restricts all movement in the area. If the successes on the Sorcery test exceed the subject's Strength, then the subject also suffers the Restrained condition (p. 56, SR6) when moving through this area.\nThe plants are not animated after the initial spell casting. They have Strength and Constitution equal to half the caster's Magic attribute, rounded up. Constitution is used to calculate the condition monitor normally. To escape them, use the grappling rules with a dice pool equal to the caster's Magic attribute for the plants." },
];

export default ALL_SPELLS;